from flask import Flask, request, jsonify
from flask_httpauth import HTTPBasicAuth
from flask_mfa import MFA
import hashlib

app = Flask(__name__)
auth = HTTPBasicAuth()
mfa = MFA(app)

@auth.verify_password
def verify_password(username, password):
    # Verify the user's credentials against a database or other authentication mechanism
    if username == 'admin' and hashlib.sha256(password.encode()).hexdigest() == 'a479fe0c3f431849a5b7439d643f532b':
        return username

@app.route('/api/login', methods=['POST'])
@auth.login_required
def login():
    # Check if MFA is enabled for the user
    if mfa.is_enabled(request.user):
        # Prompt for OTP
        otp = request.form['otp']
        if not mfa.verify_otp(request.user, otp):
            return jsonify({'error': 'Invalid OTP'}), 401
    else:
        # Grant access immediately
        pass

@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    # Skip MFA checks for API clients and automated scripts
    if request.headers.get('User-Agent') == 'API Client':
        return jsonify({'error': 'Invalid OTP'}), 401
    else:
        pass